<div class="page-header"><h1>Document Approvals</h1><p class="text-muted">Route contracts, invoices, and formal documents through a visible approval trail.</p></div><div class="row g-4"><div class="col-lg-4"><div class="card"><div class="card-body"><form method="post" action="/portal/approvals" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Document</label><select class="form-select" name="document_id"><?php foreach($documents as $d):?><option value="<?=$d['id']?>"><?=e($d['original_name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Assign to</label><select class="form-select" name="assigned_to"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>"><?=e($u['name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Comments</label><textarea class="form-control" name="comments"></textarea></div><div class="col-12"><button class="btn btn-primary">Request approval</button></div></form></div></div></div><div class="col-lg-8"><div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Document</th><th>Assigned</th><th>Status</th><th>Requested</th><th>Decision</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['original_name'])?></td><td><?=e($r['assignee']??'Unassigned')?></td><td><?=e($r['status'])?></td><td><?=e($r['requested_at'])?></td><td><?php if($r['status']==='pending'):?><form class="d-flex gap-1" method="post" action="/portal/approvals/<?=$r['id']?>/decide"><?=csrf_field()?><button name="status" value="approved" class="btn btn-sm btn-success">Approve</button><button name="status" value="rejected" class="btn btn-sm btn-outline-danger">Reject</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
